import React from "react";
import { useNavigate } from "react-router-dom";

const About = () => {
    const navigate = useNavigate();

    const handleGetStarted = () => {
        navigate("/");
    };

    return (
        <div style={{ backgroundColor: "#FAEBCD", minHeight: "100vh", padding: "40px 20px" }}>
            <div style={{
                maxWidth: "900px",
                margin: "auto",
                padding: "40px",
                backgroundColor: "#fffaf0",
                borderRadius: "16px",
                boxShadow: "0 4px 20px rgba(0,0,0,0.1)",
                textAlign: "center"
            }}>
                <h2 style={{ fontSize: "36px", fontWeight: "bold", marginBottom: "20px", color: "#4B5320" }}>
                    About Us
                </h2>
                <p style={{ fontSize: "18px", color: "#333", marginBottom: "30px", lineHeight: "1.6" }}>
                    Welcome to <strong>Agro Seva</strong>, a platform dedicated to empowering farmers by providing real-time weather updates, 
                    crop price insights, government schemes, and an advisory system to help make informed decisions.
                </p>

                <h3 style={{ fontSize: "26px", marginTop: "30px", fontWeight: "bold", color: "#6B8E23" }}>
                    Our Mission
                </h3>
                <p style={{ fontSize: "18px", color: "#333", marginBottom: "30px", lineHeight: "1.6" }}>
                    Our goal is to bridge the gap between technology and agriculture by delivering essential 
                    data and advisory services directly to farmers in a user-friendly way.
                </p>

                <h3 style={{ fontSize: "26px", marginTop: "30px", fontWeight: "bold", color: "#6B8E23" }}>
                    Why Choose Us?
                </h3>
                <ul style={{ listStyle: "none", padding: 0, fontSize: "18px", color: "#444", marginBottom: "40px" }}>
                    <li>✅ Accurate Weather Forecasts</li>
                    <li>✅ Latest Crop Price Updates</li>
                    <li>✅ Government Schemes & Benefits</li>
                    <li>✅ Expert Advisory Support</li>
                </ul>

                <button
                    onClick={handleGetStarted}
                    style={{
                        backgroundColor: "#6B8E23",
                        color: "#fff",
                        border: "none",
                        padding: "12px 30px",
                        borderRadius: "8px",
                        fontSize: "18px",
                        cursor: "pointer",
                        transition: "background-color 0.3s ease"
                    }}
                    onMouseOver={(e) => (e.target.style.backgroundColor = "#556B2F")}
                    onMouseOut={(e) => (e.target.style.backgroundColor = "#6B8E23")}
                >
                    Get Started
                </button>
            </div>
        </div>
    );
};

export default About;
